# Claude Code Account Switcher — PowerShell integration
# Generated by: Invoke-Expression (& claude-acc init pwsh)

# Prepend ~/.claude-switch/bin so the IDE wrapper for `claude` (and the
# claude-acc binary itself) is on PATH for both terminals and IDEs.
$__claude_acc_bin_dir = Join-Path $HOME ".claude-switch/bin"
if ($env:PATH -notlike "*$__claude_acc_bin_dir*") {
    $env:PATH = $__claude_acc_bin_dir + [IO.Path]::PathSeparator + $env:PATH
}

function __claude_acc_activate {
    Invoke-Expression (& '__CLAUDE_ACC_BIN__' activate --shell powershell)
}

# Hook on directory change
$ExecutionContext.SessionState.InvokeCommand.LocationChangedAction = {
    __claude_acc_activate
}

# Activate for current directory on shell startup
__claude_acc_activate

# Completions
Register-ArgumentCompleter -CommandName claude-acc -ScriptBlock {
    param($commandName, $wordToComplete, $commandAst, $fakeBoundParameters)
    $words = $commandAst.ToString() -split '\s+'
    $count = $words.Count

    if ($count -le 2) {
        $cmds = @('list','add','login','remove','default','reset','link','unlink','links','status','run','doctor','whoami','help')
        $cmds | Where-Object { $_ -like "$wordToComplete*" } | ForEach-Object {
            [System.Management.Automation.CompletionResult]::new($_, $_, 'ParameterValue', $_)
        }
    } elseif ($count -eq 3) {
        $sub = $words[1]
        $accounts = @()
        switch ($sub) {
            { $_ -in 'login','remove','run' } {
                $accounts = (& '__CLAUDE_ACC_BIN__' completions accounts) -split "`n"
            }
            { $_ -in 'default','link' } {
                $accounts = @('default') + ((& '__CLAUDE_ACC_BIN__' completions accounts) -split "`n")
            }
        }
        $accounts | Where-Object { $_ -like "$wordToComplete*" } | ForEach-Object {
            [System.Management.Automation.CompletionResult]::new($_, $_, 'ParameterValue', $_)
        }
    }
}
